'use client';

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Star, ArrowRight, Loader2, HardHat, Building2, ChevronRight, MapPin } from 'lucide-react';
import { useProjectStore } from '../store/useProjectStore';
import Link from 'next/link';

export default function Home() {
  const { projects, fetchData, addStar, isLoading } = useProjectStore() as any;
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    fetchData();
  }, [fetchData]);

  if (!mounted) return null;

  return (
    <div className="bg-[#F4F5F7] min-h-screen pt-32 pb-24">
      <section id="projets" className="px-6 max-w-[1400px] mx-auto">

        {/* --- HEADER CORPORATE --- */}
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end mb-24 gap-10">
          <div className="max-w-2xl">
            <div className="flex items-center gap-3 mb-6">
              <div className="h-[3px] w-16 bg-[#FFB800]"></div>
              <span className="text-[11px] font-black uppercase tracking-[0.4em] text-[#1A1A1A]">Expertise Panafricaine</span>
            </div>
            <h2 className="text-6xl md:text-8xl font-black uppercase tracking-tighter text-[#1A1A1A] leading-[0.8] mb-8">
              Grands <br /> <span className="text-transparent bg-clip-text bg-gradient-to-r from-gray-400 to-gray-200">Projets</span>
            </h2>
            <p className="text-gray-500 font-medium text-lg leading-relaxed border-l-2 border-gray-200 pl-6 italic">
              "Bâtir des infrastructures durables pour l'émergence du continent."
            </p>
          </div>

          {/* STATUS BOARD */}
          <div className="bg-[#1A1A1A] p-6 shadow-2xl flex items-center gap-8 min-w-[300px]">
            <div className="flex flex-col">
              <span className="text-[9px] font-black text-[#FFB800] uppercase tracking-widest">Base de Données</span>
              <div className="flex items-center gap-2 mt-1">
                {isLoading ? <Loader2 size={14} className="animate-spin text-white" /> : <div className="w-2 h-2 bg-green-500 rounded-full"></div>}
                <span className="text-xs font-bold text-white uppercase">{isLoading ? 'Synchronisation...' : 'Opérationnelle'}</span>
              </div>
            </div>
            <div className="h-10 w-[1px] bg-white/10"></div>
            <div className="flex flex-col text-white">
              <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Ouvrages</span>
              <span className="text-xl font-black">{projects?.length || 0}</span>
            </div>
          </div>
        </div>

        {/* --- GRILLE DE RÉALISATIONS --- */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-x-12 gap-y-20">
          <AnimatePresence mode="popLayout">
            {projects.map((project: any, index: number) => (
              <motion.div
                key={project.id}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                viewport={{ once: true }}
                className="group relative"
              >
                {/* NUMÉRO D'INDEX (Style Luxe) */}
                <span className="absolute -top-8 left-0 text-5xl font-black text-gray-100 group-hover:text-[#FFB800]/20 transition-colors pointer-events-none">
                  0{index + 1}
                </span>

                {/* VISUEL PRINCIPAL */}
                <div className="relative h-[450px] w-full overflow-hidden shadow-2xl bg-gray-200">
                  <img
                    src={project.images?.[0] || "https://images.unsplash.com/photo-1541888946425-d81bb19480c5?q=80&w=2070&auto=format&fit=crop"}
                    alt={project.title}
                    className="w-full h-full object-cover grayscale group-hover:grayscale-0 group-hover:scale-105 transition-all duration-1000"
                  />

                  {/* OVERLAY TECHNIQUE */}
                  <div className="absolute inset-0 bg-gradient-to-t from-[#1A1A1A]/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

                  {/* BADGE TYPE */}
                  <div className="absolute top-6 left-6 bg-white text-black font-black px-4 py-2 text-[10px] uppercase tracking-[0.2em] shadow-xl border-b-2 border-[#FFB800]">
                    {project.type}
                  </div>
                </div>

                {/* CONTENU INFO */}
                <div className="mt-8">
                  <div className="flex justify-between items-start gap-4 mb-4">
                    <h3 className="font-black text-3xl uppercase tracking-tighter text-[#1A1A1A] leading-tight">
                      {project.title}
                    </h3>
                    <button
                      onClick={() => addStar(project.id)}
                      className="mt-2 flex items-center gap-1.5 hover:scale-110 transition-transform"
                    >
                      <Star size={16} fill={project.stars > 0 ? "#FFB800" : "none"} className={project.stars > 0 ? "text-[#FFB800]" : "text-gray-300"} />
                      <span className="text-xs font-black text-gray-400">{project.stars || 0}</span>
                    </button>
                  </div>

                  <p className="text-gray-500 text-sm leading-relaxed mb-6 line-clamp-2 font-medium">
                    {project.description}
                  </p>

                  <div className="flex items-center justify-between pt-6 border-t border-gray-200">
                    <div className="flex flex-col">
                      <span className="text-[8px] font-black text-[#FFB800] uppercase tracking-widest mb-1">Partenaire Projet</span>
                      <span className="text-[11px] font-bold text-[#1A1A1A] uppercase">{project.client}</span>
                    </div>

                    <Link href="/contact" className="flex items-center gap-3 bg-[#1A1A1A] text-white px-6 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-[#FFB800] hover:text-black transition-all group/btn shadow-lg">
                      Expertise <ChevronRight size={14} className="group-hover/btn:translate-x-1 transition-transform" />
                    </Link>
                  </div>
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>

        {/* --- EMPTY STATE PROFESSIONNEL --- */}
        {!isLoading && projects.length === 0 && (
          <div className="py-40 text-center bg-white border-y border-gray-100 shadow-sm">
             <Building2 size={48} className="mx-auto text-gray-100 mb-6" />
             <h3 className="text-xs font-black uppercase tracking-[0.4em] text-gray-300">Aucun dossier archivé</h3>
          </div>
        )}
      </section>
    </div>
  );
}